import os, base64
TARGET = 'C:/Users/26772/osh website/worker-portal.js'
B64 = ''
def write_js():
    js = base64.b64decode(B64).decode("utf-8")
    with open(TARGET, "w", encoding="utf-8") as f: f.write(js)
    size = len(js)
    print("Generated worker-portal.js (%d bytes)" % size)
if __name__ == "__main__": write_js()
